from sys import stdin
from string import ascii_uppercase


def dfs(i):
    if i == len(s):
        return True

    for r in range(2):
        for c in range(13):
            if not grid[r][c] and check(r, c):
                grid[r][c] = s[i]
                if dfs(i + 1):
                    return True
                grid[r][c] = 0

    return False


def check(r, c):
    for dr, dc in [(0, 1), (1, 0), (1, 1), (-1, 1)]:
        nr, nc = r + dr, c + dc
        if 0 <= nr < 2 and 0 <= nc < 13 and grid[nr][nc] == s[i]:
            return False

    return True


s = stdin.readline().strip()
grid = [[0] * 13 for _ in range(2)]

if dfs(0):
    for row in grid:
        print(''.join(ascii_uppercase[i] for i in row).replace('0', ''))
else:
    print('Impossible')
